df_gene_num <- read.table(file = "df_gene_num.txt",
                          sep = "\t",row.names = 1,header = T)
## 2.1 data processing
df_gene_num$group <- rownames(df_gene_num)
df_gene_num2 <- pivot_longer(df_gene_num,cols = c("Up_num","Down_num"),
                             values_to = "gene_num",names_to = "updown")
df_up <- df_gene_num2[df_gene_num2$updown=="Up_num",] %>% 
  arrange(group)
df_down <- df_gene_num2[df_gene_num2$updown=="Down_num",] %>% 
  arrange(group)
df_down$gene_num <- -df_down$gene_num
## 2.3 barplot2
df_gene_num3 <- df_gene_num[-c(grep("mlncRNA",df_gene_num$group),
                               grep("tRNA_merge",df_gene_num$group)),] %>% 
  mutate(group2=sub("^(.*?)_.*$", "\\1", group)) %>% 
  mutate(group2=factor(group2,levels=c("miRNA","tRNA","piRNA","mRNA","lncRNA"))) %>% 
  mutate(group3=sub("^.*_.*_(.*)_.*$", "\\1", group)) %>% 
  mutate(group3=gsub("CF.R","AST",group3)) %>% 
  mutate(group3=gsub("CF.S","OLI",group3)) %>% 
  mutate(group3=gsub("CF.W","AZO",group3)) %>% 
  mutate(group3=factor(group3,levels=c("AST","OLI","AZO"))) %>% 
  mutate(group=factor(group,levels=.$group[order(.$group2)]))
