AZS_pathway <- read.table(file = "./AZS/GSEA_GO_BP_res.txt",sep = "\t",header = T,row.names = NULL,fill = T)
OLI_pathway <- read.table(file = "./OLI/GSEA_GO_BP_res.txt",sep = "\t",header = T,row.names = NULL,fill = T)
AZO_pathway <- read.table(file = "./AZO/GSEA_GO_BP_res.txt",sep = "\t",header = T,row.names = NULL,fill = T)
AZS_pathway_up <- AZS_pathway %>% 
  filter(p.adjust<0.05) %>% 
  filter(NES>0) %>% 
  arrange(-NES) %>% 
  slice(1:16)
OLI_pathway_up <- OLI_pathway %>%
  filter(p.adjust<0.05) %>% 
  filter(NES>0) %>% 
  arrange(-NES) %>% 
  slice(1:16)
AZO_pathway_up <- AZO_pathway %>%
  filter(p.adjust<0.05) %>%
  filter(NES>0) %>%
  arrange(-NES) %>% 
  slice(1:16)
all_id_up_df <- bind_rows(AZS_pathway_up,OLI_pathway_up,AZO_pathway_up) %>% 
  dplyr::select(1,2) %>% 
  unique()
all_id_up <- unique(c(AZS_pathway_up$ID,OLI_pathway_up$ID,AZO_pathway_up$ID))
length(all_id_up) # 共有多少上调通路
AZS_pathway_down <- AZS_pathway %>%
  filter(p.adjust<0.05) %>%
  filter(NES<0) %>%
  arrange(NES) %>% 
