### 2.ggplot data ####
up_cluster <- read.table(file = "./inputdata/up_GOterm.txt",sep = "\t",header = T,
                         row.names = NULL)
down_cluster <- read.table(file = "./inputdata/down_GOterm.txt",sep = "\t",header = T,
                           row.names = NULL)
grps <- c("AZS","OLI","AZO")
for (i_grp in grps) {
  df <- read.table(file = paste0("../GSEA_GO_KEGG3/",i_grp,"/GSEA_GO_BP_res.txt"),
                   sep = "\t",header = T,row.names = NULL,fill = T)
  up_df <- df[match(up_cluster$id,df$ID),] %>% 
    merge(up_cluster,.,by.y="ID",by.x="id",all.y = T)
  down_df <- df[match(down_cluster$id,df$ID),] %>% 
    merge(down_cluster,.,by.y="ID",by.x="id",all.y = T)
  assign(paste0(i_grp,"_up"),up_df)
  assign(paste0(i_grp,"_down"),down_df)
}
all_up <- rbind(AZS_up,OLI_up,AZO_up) %>% 
  mutate(p_adj=-log10(p.adjust)) %>% 
  na.omit() %>% 
  filter(p.adjust<0.05) %>% 
  mutate(cluster=factor(cluster,levels=1:length(unique(cluster)))) %>% 
  mutate(group=factor(group,levels=c("AZS","OLI","AZO"))) %>% 
  group_by(Description) %>% 
  mutate(group_num = n()) %>% 
  ungroup() %>% 
  arrange(desc(group_num),desc(cluster),desc(group),-p_adj) %>%
  # mutate(Description=factor(Description,levels=unique(.$Description)[c(2,1,3,4,6,7,5,8,16,18,9,11,12,10,13,15,17,14)]))
  mutate(Description=factor(Description,levels=unique(Description)))
write.table(all_up,file = "./outputdata/all_up.txt",sep = "\t",
            col.names = T,row.names = F,quote = F)
write.table(unique(all_up[2:3]),file = "./outputdata/all_up_GOterm.txt",sep = "\t",
            col.names = F,row.names = F,quote = F)


all_down <- rbind(AZS_down,OLI_down,AZO_down) %>% 
  mutate(p_adj=-log10(p.adjust)) %>% 
  mutate(NES=-NES) %>% 
  na.omit() %>% 
  filter(p.adjust<0.05) %>% 
  mutate(cluster=factor(cluster,levels=1:length(unique(cluster)))) %>% 
  mutate(group=factor(group,levels=c("AZS","OLI","AZO"))) %>% 
  group_by(Description) %>% 
  mutate(group_num = n()) %>% 
  ungroup() %>% 
  arrange(desc(group_num),desc(cluster),desc(group),-p_adj) %>%
  # mutate(Description=factor(Description,levels=unique(.$Description)[c(3,2,1,7,9,4,8,5,6,15,11,12,13,14,16,10,17,19,18)]))
  mutate(Description=factor(Description,levels=unique(Description)))
write.table(all_down,file = "./outputdata/all_down.txt",sep = "\t",
            col.names = T,row.names = F,quote = F)
write.table(unique(all_down[2:3]),file = "./outputdata/all_down_GOterm.txt",sep = "\t",
            col.names = F,row.names = F,quote = F)

