##Fig2E number of pachytene piRNA
library(ggplot2)
library(tidyr)
library(dplyr)
library(readxl)

data <- read_excel("piRNA.xlsx", sheet = "Sheet1")
colnames(data) <- c("Period", "AZS_Up", "AZS_Down", "OLI_Up", 
                    "OLI_Down", "AZO_up", "AZO_down", "Not_detected")

data_long <- data %>%
    filter(!is.na(Period)) %>%
  select(Period, AZS_Up, AZS_Down, OLI_Up, OLI_Down, AZO_up, AZO_down, Not_detected) %>%
  pivot_longer(cols = -Period, 
               names_to = "Category", 
               values_to = "Count") %>%
  mutate(
    Disease = case_when(
      Category == "Not_detected" ~ "AZO",
      grepl("AZS", Category) ~ "AZS",
      grepl("OLI", Category) ~ "OLI", 
      grepl("AZO", Category) ~ "AZO"
    ),
    Direction = case_when(
      Category == "Not_detected" ~ "Not_detected",
      grepl("_Up|_up", Category) ~ "Up",
      grepl("_Down|_down", Category) ~ "Down"
    ),
    Count = as.numeric(Count)
  ) %>%
  select(-Category)

# 
stack_data <- data_long %>%
  pivot_wider(names_from = Period, values_from = Count)

stack_data <- stack_data %>%
  mutate(
    Direction_ordered = case_when(
      Disease == "AZO" ~ factor(Direction, levels = c("Up", "Down", "Not_detected")),
      TRUE ~ factor(Direction, levels = c("Up", "Down"))
    )
  )


library(ggbreak)
library(patchwork) 
stack_data <- stack_data %>%
  mutate(Disease = factor(Disease, levels = c("AZS", "OLI", "AZO")))

pdf('Fig2E.barchart of pachytene piRNA.pdf')
ggplot() +
  geom_bar(data = stack_data, 
           aes(x = Direction_ordered, y = Total, fill = Direction_ordered),  # 修改：根据方向设置填充色
           stat = "identity", width = 0.5, 
           alpha = 0.8, position = position_dodge2(preserve = "single")) +
  geom_bar(data = stack_data, 
           aes(x = Direction_ordered, y = Pachytene), 
           stat = "identity", width = 0.5, alpha = 0.8, 
           fill = "#FF6B6B",  # color of Pachytene
           position = position_dodge2(preserve = "single")) +
  # 添加标签
  geom_text(data = stack_data,
            aes(x = Direction_ordered, y = Pachytene, label = Pachytene, group = Direction_ordered), 
            position = position_dodge2(width = 0.7, preserve = "single"),
            vjust = 0.5, size = 3, color = "white", fontface = "bold") +
  geom_text(data = stack_data,
            aes(x = Direction_ordered, y = Total, label = Total, group = Direction_ordered), 
            position = position_dodge2(width = 0.7, preserve = "single"),
            vjust = -0.5, size = 3, fontface = "bold") +
  facet_wrap(~ Disease, scales = "free_x", nrow = 1) +
  labs(title = "不同疾病类型中piRNA表达变化数量",
       x = "表达方向",
       y = "piRNA数量",
       fill = "表达方向") +  # 修改：图例标题改为"表达方向"
  # 修改：自定义颜色比例尺
  scale_fill_manual(
    values = c(
      "Up" = "#FF6B9D",    # 粉红色
      "Down" = "#4ECDC4",  # 青蓝色
      "Not_detected" = "#FFD166"  # 金黄色
    ),
    breaks = c("Up", "Down", "Not_detected"),  # 指定图例顺序
    labels = c("上调", "下调", "未检测到")  # 可选：自定义图例标签
  ) +
  scale_x_discrete(labels = function(x) {
    ifelse(x == "Not_detected", "Not_detected", x)
  }) +
  scale_y_continuous(expand = c(0,0)) +
  expand_limits(y = 11000) +
  scale_y_break(c(1000, 3000), scales = 0.1, ticklabels = c(3000, 4000, 5000), space = 0.1) + 
  scale_y_break(c(5000, 9000), scales = 0.1, ticklabels = c(9000, 9500, 10000), space = 0.1) +
  theme_classic() +
  theme(
    axis.text.x = element_text(angle = 45, hjust = 1),
    axis.text.y = element_blank(),
    axis.ticks.y = element_blank(), 
    plot.title = element_text(hjust = 0.5, face = "bold"),
    strip.background = element_rect(fill = "lightgray"),
    legend.position = "top"
  )
dev.off()

