#Fig3A. volcano plot of DE in AZO with marked genes
library(ggrepel)
library(dplyr)
DE_AZO <- data.frame(read.table('D:/项目/精浆cfRNA/分析结果/Exp/DEG/DEG/20230815_zq_semenDEGs/outputdata/mlncRNA_count_CF.W_DEGs.txt',header = T,row.names = 1,sep="\t"))
gene_data <- data.frame(Gene=DE_AZO$gene,Log2FC=DE_AZO$log2FoldChange,PValue=DE_AZO$padj)
gene_data$NegLog10P <- -log10(gene_data$PValue)
log2fc_threshold <- 1
pval_threshold <- 0.05

gene_data <- gene_data %>%
  mutate(Significant = case_when(
    NegLog10P > -log10(pval_threshold) & Log2FC > log2fc_threshold ~ "Up",
    NegLog10P > -log10(pval_threshold) & Log2FC < -log2fc_threshold ~ "Down",
    TRUE ~ "Not Sig"
  ))
genes_of_interest <- c("PRM1","SPATA3","SPATA42","PRM2","DMC1","DMRT1","MEIOB",
                       "PDHA2","SPO11","TDRD9","TEX15","MEI1","PNLDC1","HIWI","MSH4","SPATA22")
#"MEIOB","NR5A1","MEI1","TEX11"
# 修改Label列
gene_data <- gene_data %>%
  mutate(Label = if_else(
    Gene %in% genes_of_interest,
    as.character(Gene),
    ""
  ))
p <- ggplot(data = gene_data, aes(x = Log2FC, y = NegLog10P)) +
  geom_point(aes(color = Significant), alpha = 0.6, size = 1.5) + # 根据显著性上色
  scale_color_manual(values = c("Down" = "lightblue", "Not Sig" = "grey", "Up" = "pink")) +
  #theme_minimal() + # 简洁的主题
  theme_classic()+
  labs(
    x = expression("Log"[2]*" Fold Change"),
    y = expression("-Log"[10]*" P-value"),
    title = "",
    color = "Regulation"
  ) +
  geom_vline(xintercept = c(-log2fc_threshold, log2fc_threshold), linetype = "dashed", color = "black", alpha = 0.5) +
  geom_hline(yintercept = -log10(pval_threshold), linetype = "dashed", color = "black", alpha = 0.5)
p_with_labels <- p + geom_text_repel(
  data = subset(gene_data, Label != ""), # 只对Label不为空的点进行标注
  aes(label = Label),
  size = 5,
  box.padding = 0.6, # 调整标签与点之间的距离
  point.padding = 0.3,
  max.overlaps = 30, # 最大允许的重叠数，可调整
  segment.color = 'grey50', # 连接线的颜色
  show.legend = FALSE # 不显示标签的图例
)
pdf('Fig3A.DE_AZO_volcano.pdf')
print(p_with_labels)
dev.off()


