############## Fig 4
#Fig4A. pipeline of model generated by Biorender

#Fig4B-C. scatter of predicted value(sperm number and PR)
library(ggplot2)
library(FNN)
library(broom)
# 读取数据
df <- read.csv("num_scatter_plot.csv", row.names = 1)
df <- read.csv("PR_scatter_plot.csv", row.names = 1)
# 定义距离阈值
dist_threshold <- 10  # 调整为合理的距离阈值
# 使用get.knnx找到每个点的邻近点
train_data <- as.matrix(df[, c("x", "y")])
test_data <- as.matrix(df[, c("x", "y")])
# 计算所有点之间的距离矩阵
dist_matrix <- dist(train_data, method = "euclidean")
# 将距离矩阵转换为邻接矩阵
adj_matrix <- as.matrix(dist(train_data, method = "euclidean")) <= dist_threshold
# 计算每个点的邻近点数量
neighbor_counts <- rowSums(adj_matrix) - 1  # 减去自身
# 将邻近点数量作为颜色变量
df$color_value <- neighbor_counts
# 进行线性回归并提取统计信息
fit <- lm(y ~ x, data = df)
summary_fit <- summary(fit)
conf_int <- confint(fit)
# 提取R²、RMSE和Pearson相关系数
r_squared <- summary_fit$r.squared
rmse <- sqrt(mean(residuals(fit)^2))
pearson_corr <- cor(df$x, df$y)
# 创建散点图，并添加拟合直线和置信区间
p <- ggplot(df, aes(x = x, y = y)) +
  geom_point(aes(color = color_value), size = 3) +  # 根据color_value设置颜色渐变
  geom_smooth(method = "lm", se = TRUE, color = "black", fill = "gray60", alpha = 0.3) +  # 添加线性回归拟合直线和置信区间
  scale_color_gradient(name = "n_neighbors", low = "darkblue", high = "yellow") +  # 设置颜色渐变范围和legend标题
  labs(title = "Scatter Plot with Fitted Line and Gradient Colors",
       x = "Sperm Count",
       y = "Predicted Sperm Count") +
  theme_minimal() +
  theme(panel.grid.major = element_blank(), panel.grid.minor = element_blank()) +  # 去除背景网格
  theme(axis.line = element_line(colour = "black", size = 0.5)) +  # 显示坐标轴的线本身
  theme(axis.title.x = element_text(size = 14 * 1.5), axis.title.y = element_text(size = 14 * 1.5)) +  # 坐标轴标题文字大小增加一倍
  theme(axis.text.x = element_text(size = 12 * 1.5), axis.text.y = element_text(size = 12 * 1.5)) +  # 坐标轴刻度文字大小增加一倍
  theme(legend.title = element_text(size = 12 * 1.5)) +  # legend标题文字大小增加一倍
  annotate("text", x = min(df$x), y = max(df$y),
           label = paste("R² =", round(r_squared, 2), "\nRMSE =", round(rmse, 2), "\nPearson =", round(pearson_corr, 2)),
           hjust = 0, vjust = 1, color = "black", size = 4)

pdf("Fig4B.num_scatter.final.pdf")
print(p)
dev.off()
